return ['domain'=>NULL,'plural-forms'=>'nplurals=2; plural=(n != 1);','language'=>'ca','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Si us plau, actualitza el connector TranslatePress - Multilingual a la versió %1$s o superior per assegurar que %2$s funcioni correctament.','Please install and activate the TranslatePress - Multilingual plugin'=>'Si us plau, instal·la i activa el connector TranslatePress - Multilingual','Install & Activate'=>'Instal·la i activa','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Si us plau, actualitza TranslatePress - Multilingual a la versió %2$s o més recent. La versió actualment instal·lada de TranslatePress - Multilingual ja no és compatible amb la versió actual de %1$s.','All TranslatePress functionalities are disabled until then.'=>'Totes les funcionalitats de TranslatePress estan desactivades fins llavors.','Update Now'=>'Actualitza ara','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Aquest complement de TranslatePress s\'ha migrat al connector principal i ja no s\'utilitza. Pots suprimir-lo.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> requereix almenys la versió 5.6.20+ de PHP per funcionar. És el requisit mínim de la <a href="%s">versió més recent de WordPress</a>. Posa\'t en contacte amb l\'administrador del servidor per actualitzar la teva versió de PHP.','Advanced'=>'Avançada','Settings saved.'=>'S\'han desat els paràmetres.','Are you sure you want to remove this item?'=>'Segur que vols suprimir aquest element?','Remove'=>'Suprimeix','Add'=>'Afegeix','Select...'=>'Selecciona...','[%s] Low TranslatePress AI Words'=>'[%s] Nivell baix de paraules de TranslatePress AI','upgrade your plan or get extra AI Words'=>'actualitza el teu pla o aconsegueix paraules d\'IA extra','upgrade your plan'=>'actualitza el teu pla','TranslatePress AI words are running low on your site.'=>'Les paraules de TranslatePress AI s\'estan acabant al teu lloc.','Current status: %s words remaining'=>'Estat actual: %s paraules restants','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Un cop s\'esgotin les paraules d\'IA restants, la traducció automàtica mitjançant TranslatePress AI es pausarà.','To continue translating your content, please %1$s over at %2$s'=>'Per continuar traduint el contingut, si us plau %1$s a %2$s','Manage Notification: %s'=>'Gestiona la notificació: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Hi ha una nova versió de %1$s disponible. %2$sVeure els detalls de la versió %3$s%4$s o %5$sactualitza ara%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Hi ha una nova versió de %1$s disponible. %2$sVeure els detalls de la versió %3$s%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'Per habilitar les actualitzacions, si us plau %1$sintrodueix la clau de llicència%2$s. Necessites una clau de llicència? %3$sCompra\'n una ara%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'Per habilitar les actualitzacions, vés a la %1$spàgina de llicència%2$s i comprova que tens una llicència vàlida.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'Per habilitar les actualitzacions, cal renovar la teva llicència. Si us plau, vés a la pàgina %1$sTranslatePress Account%2$s i inicia la sessió per renovar-la.','You do not have permission to install plugin updates'=>'No tens permís per instal·lar actualitzacions de connectors','Error'=>'Error','Your TranslatePress license key is invalid or missing.'=>'La clau de llicència de TranslatePress no és vàlida o falta.','Your license key expired on %s.'=>'La teva clau de llicència va caducar el %s.','Your license key has been disabled.'=>'La teva clau de llicència s\'ha desactivat.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'La teva clau de llicència està desactivada per a aquesta URL. Torna a activar-la des de <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>La clau de llicència no coincideix.</strong> La llicència que has introduït no coincideix amb la versió de TranslatePress que tens instal·lada.</p><p>Si us plau, comprova que has instal·lat la versió correcta per a la teva llicència des del teu compte de TranslatePress.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Si només tens instal·lat el connector gratuït però has afegit una llicència de pagament, si us plau, instal·la el connector de pagament des del teu compte de TranslatePress.','Your license key has reached its activation limit.'=>'La teva clau de llicència ha arribat al límit d\'activacions.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Millora el teu pla per afegir més llocs. %1$sMillora ara%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Aquest lloc web ja està activat amb una llicència gratuïta. Cada lloc web només pot utilitzar una llicència gratuïta.','An error occurred, please try again.'=>'S\'ha produït un error, si us plau, torna-ho a provar.','You have successfully activated your license'=>'Has activat la llicència correctament.','Others'=>'Altres','Restrict by Language'=>'Restringir per idioma','Exclude from Language'=>'Excloure de l\'idioma','Restrict element to language'=>'Restringir l\'element a un idioma','Show this element only in one language.'=>'Mostrar aquest element només en un idioma.','Enable translation'=>'Habilitar la traducció','Allow translation to the corresponding language only if the content is written in the default language.'=>'Permetre la traducció a l\'idioma corresponent només si el contingut està escrit en l\'idioma per defecte.','Select language'=>'Seleccionar l\'idioma','Choose in which language to show this element.'=>'Trieu en quin idioma mostrar aquest element.','Exclude element from language'=>'Excloure l\'element de l\'idioma','Exclude this element from specific languages.'=>'Excloure aquest element d\'idiomes específics.','Select languages'=>'Seleccionar idiomes','Choose from which languages to exclude this element.'=>'Trieu de quins idiomes excloure aquest element.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Aquest element encara serà visible quan traduïu el vostre lloc web a través de l\'Editor de traducció.','The content of this element should be written in the default language.'=>'El contingut d\'aquest element s\'ha d\'escriure en l\'idioma per defecte.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> ha trobat errors SQL. <a href="%s" title="Veure els errors SQL de TranslatePress">Consulteu els errors</a>.','Automatic translation has been disabled.'=>'S\'ha desactivat la traducció automàtica.','Dismiss this notice.'=>'Descartar aquest avís.','Logged errors'=>'Errors registrats','These are the most recent 5 errors logged by TranslatePress:'=>'Aquests són els 5 errors més recents registrats per TranslatePress:','Yes'=>'Sí','Why are these errors occuring'=>'Per què es produeixen aquests errors','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Si TranslatePress detecta algun problema quan executa consultes a la base de dades, pot desactivar la funció de traducció automàtica per evitar càrrecs addicionals per part de Google/DeepL. La traducció automàtica s\'ha d\'activar manualment després de resoldre els problemes.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'Els errors de SQL detectats es poden produir per diversos motius, incloent-hi taules inexistents, falta de permisos per a l\'usuari de SQL per crear taules o realitzar altres operacions, problemes després de la migració del lloc o canvis a la configuració del servidor de SQL.','What you can do in this situation'=>'Què pots fer en aquesta situació','Plan A.'=>'Pla A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Ves a Configuració -> TranslatePress -> Pestanya General i desa la configuració. Això regenerarà les taules amb la teva configuració actual de SQL. Comprova que no es produeixen més errors mentre navegues pel teu lloc web en un idioma traduït. Fixa\'t en les marques de temps dels errors per assegurar-te que no estàs veient els errors antics. Només es mostren els 5 errors més recents.','Plan B.'=>'Pla B.','If your problem isn\'t solved, try the following steps:'=>'Si el teu problema no es resol, prova els passos següents:','Create a backup of your database'=>'Crea una còpia de seguretat de la teva base de dades','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Crea una còpia de cada taula de traducció on trobis errors. Pots copiar la taula dins de la mateixa base de dades (per exemple, trp_dictionary_en_us_es_es_COPY) -- realitza aquest pas només si vols conservar les traduccions actuals.','Remove the trouble tables by executing the DROP function on them'=>'Elimina les taules problemàtiques executant la funció DROP sobre elles','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Ves a Configuració -> TranslatePress -> Pestanya General i desa la configuració. Això regenerarà les taules amb el teu servidor de SQL actual.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Copia el contingut rellevant de les taules duplicades (per exemple, trp_dictionary_en_us_es_es_COPY) a la taula generada recentment (trp_dictionary_en_us_es_es) -- realitza aquest pas només si vols conservar les traduccions actuals.','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Comprova-ho per veure si tot funciona correctament. Si alguna cosa ha anat malament, pots restaurar la còpia de seguretat que has fet al primer pas. Comprova que no es produeixen més errors mentre navegues pel teu lloc web en un idioma traduït. Fixa\'t en les marques de temps dels errors per assegurar-te que no estàs veient els errors antics. Només es mostren els 5 errors més recents.','Plan C.'=>'Pla C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Si el teu problema encara no es resol, prova de consultar els teus errors amb el teu allotjament. El problema més habitual és la manca de permisos per a l\'usuari de SQL, com ara el permís per crear taules.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'No s\'ha pogut instal·lar. Torna-ho a provar des del <a href="%s" >Tauler de complements.</a>','Active'=>'Actiu','Permission denied.'=>'Permís denegat.','Invalid nonce.'=>'Nonce no vàlid.','Settings scope unknown.'=>'Àmbit de configuració desconegut.','Legacy disabled.'=>'Mode antic desactivat.','Language Switcher'=>'Selector d\'idioma','Change language to %s'=>'Canvia l\'idioma a %s','Automatic Translation'=>'Traducció automàtica','DeepL'=>'DeepL','Unsupported languages'=>'Idiomes no compatibles','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'El motor de traducció automàtica seleccionat no admet aquests idiomes.<br>Podeu continuar traduint manualment les pàgines en aquests idiomes amb l\'Editor de traducció.','API key validation failed.'=>'La validació de la clau de l\'API ha fallat.','API key verification was successful.'=>'La verificació de la clau de l\'API ha estat correcta.','Please enter your Google Translate key.'=>'Introduïu la clau de Google Translate.','Please enter your DeepL API key.'=>'Introduïu la clau de l\'API de DeepL.','Not TranslatePress onboarding page.'=>'No és la pàgina de benvinguda de TranslatePress.','Step %s does not exist'=>'El pas %s no existeix','Welcome'=>'Benvinguda','Add Languages'=>'Afegeix idiomes','Enable Addons'=>'Activa complements','Finalize'=>'Finalitza','Exit Setup'=>'Surt de la configuració','Upgrade'=>'Actualitza','Nothing here'=>'No hi ha res','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'La teva llicència de <strong>TranslatePress</strong> no existeix o no és vàlida. <br/>Si us plau, %1$sregistra la teva còpia%2$s per habilitar la traducció automàtica del lloc web mitjançant TranslatePress AI, els complements premium, les actualitzacions automàtiques i el suport. Necessites una clau de llicència? %3$sCompra-ne una ara%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'La teva llicència de <strong>TranslatePress</strong> caducarà el %1$s. Si us plau, %2$srenova la teva llicència%3$s per seguir tenint accés a les traduccions automàtiques mitjançant TP AI, els complements premium, les descàrregues de productes i les actualitzacions automàtiques. %4$sRenova ara%5$s','Error: '=>'Error: ','Something went wrong, please try again.'=>'S\'ha produït un error, si us plau, torna-ho a provar.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'La teva llicència de <strong>TranslatePress</strong> ha caducat. <br/>Si us plau, %1$srenova la teva llicència%2$s per seguir tenint accés a les traduccions automàtiques mitjançant TranslatePress AI, els complements premium, les descàrregues de productes i les actualitzacions automàtiques. %3$sRenova ara %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'La clau de llicència no coincideix. La llicència que has introduït no coincideix amb la versió <strong>%1$s</strong> que tens instal·lada. <br/>Si us plau, comprova que has instal·lat la versió correcta per a la teva llicència des del teu %2$scompte de TranslatePress%3$s.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Si tens instal·lat només el connector gratuït però has afegit una llicència de pagament, si us plau, instal·la el connector de pagament des del teu compte de TranslatePress.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Has arribat al límit d\'activació per a la teva llicència <strong>%1$s</strong>. <br/>Gestiona els teus llocs actius des del %2$s teu compte %3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'La teva llicència està desactivada per a aquesta URL. Torna a activar-la des de <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Gestiona els llocs.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'La traducció automàtica de %1$s requereix una llicència activa. Si us plau, %2$srenova%3$s la teva llicència o compra\'n una de nova %4$saquí%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Si us plau, %1$sintrodueix%2$s la teva clau de llicència per habilitar la traducció automàtica de %3$s.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Et queden menys de 5.000 paraules de TranslatePress AI. Per continuar traduint automàticament el teu lloc web, si us plau, %scompra paraules d\'IA addicionals amb descompte des del teu compte%s.',' Error: '=>' Error: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Aquest lloc web ja està activat amb una llicència gratuïta. Cada lloc web només pot utilitzar una llicència gratuïta. Si us plau, actualitza a un pla premium per obtenir més paraules de TranslatePress AI des del %1$s teu compte %2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'No tens una llicència vàlida per a <strong>TranslatePress</strong>. %1$sAconsegueix-ne una de gratuïta%2$s per accedir a TranslatePress AI.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>NOVETAT:</strong> L\'extensió <strong>Domini diferent per idioma</strong> ja és aquí! Potencia el teu SEO global i crea una experiència local amb dominis específics per país com .de o .fr. Actualitza a <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> per accedir-hi i a més avantatges premium!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>NOVETAT:</strong> L\'extensió <strong>Domini diferent per idioma</strong> ja és aquí! Potencia el teu SEO global i crea una experiència local amb dominis específics per país com .de o .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Més informació</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'S\'ha excedit la quota diària de caràcters de traducció automàtica. Si us plau, consulta la pàgina <strong>TranslatePress -> <a href="%s">Traducció automàtica</a></strong> per a més informació.','Marketing optin'=>'Subscripció de màrqueting','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Subscriviu-vos per rebre les notificacions d\'actualitzacions de seguretat i funcions, així com el seguiment diagnòstic no sensible.','TranslatePress Preferred User Language'=>'Idioma preferit de l\'usuari de TranslatePress','Preferred language to navigate the site'=>'Idioma preferit per navegar pel lloc','The language is automatically set based by the last visited language by the user.'=>'L\'idioma s\'estableix automàticament en funció de l\'últim idioma visitat per l\'usuari.','Always use this language'=>'Utilitza sempre aquest idioma','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Si activeu aquesta opció, l\'idioma preferit romandrà el seleccionat a dalt, sense que es pugui canviar des del frontal.<br>Aquest idioma s\'utilitzarà en diferents operacions, com ara l\'enviament de correus electrònics a l\'usuari.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Hola! Sembla que fa un temps que utilitzeu <strong>TranslatePress</strong> per traduir el vostre lloc web. Això és fantàstic! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Si podeu dedicar uns moments a valorar-lo a WordPress.org, ens ajudarà molt (i reforçarà la meva motivació).','~ Razvan, developer of TranslatePress'=>'~ Razvan, desenvolupador de TranslatePress','Rate TranslatePress on WordPress.org plugin page'=>'Valora TranslatePress a la pàgina del connector de WordPress.org','Ok, I will gladly help!'=>'D\'acord, hi ajudaré encantat!','No, thanks.'=>'No, gràcies.','Full Language Names'=>'Noms complets d\'idioma','Short Language Names'=>'Noms abreviats d\'idioma','Flags with Full Language Names'=>'Banderes amb noms complets d\'idioma','Flags with Short Language Names'=>'Banderes amb noms abreviats d\'idioma','Only Flags'=>'Només banderes','Full Language Names No HTML'=>'Noms complets d\'idioma sense HTML','Bottom Right'=>'A baix a la dreta','Bottom Left'=>'A baix a l\'esquerra','Top Right'=>'Dalt a la dreta','Top Left'=>'Dalt a l\'esquerra','Dark'=>'Fosc','Light'=>'Clar','Deactivate'=>'Desactiva','Activate'=>'Activa','Invalid language code. Please try again.'=>'Codi d\'idioma no vàlid. Si us plau, torneu-ho a provar.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Els codis d\'idioma només poden contenir caràcters A-Z a-z 0-9 - _. Comproveu els codis d\'idioma a la Configuració general de TranslatePress.','Error! Duplicate URL slug values.'=>'Error! Slugs d\'URL duplicats.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'No podeu seleccionar dos idiomes que tinguin el mateix <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">codi ISO</a> però diferents formalitats, perquè fer-ho provocarà <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">etiquetes hreflang</a> duplicades.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'S\'ha detectat un idioma duplicat.<br>Cada idioma només es pot afegir una vegada per garantir una gestió de traduccions precisa.<br> Canvieu l\'entrada d\'idioma duplicada i torneu-ho a provar. ','Current Language'=>'Idioma actual','Opposite Language'=>'Idioma oposat','General'=>'General','Translate Site'=>'Traduir el lloc','Addons'=>'Complements','License'=>'Llicència','Settings'=>'Configuració','Activate License'=>'Activa la llicència','Pro Features'=>'Funcions Pro','Need Help?'=>'Necessites ajuda?','Recent community discussions'=>'Debats recents de la comunitat','Loading...'=>'S\'està carregant...','Unable to load forum posts'=>'No s\'han pogut carregar les entrades del fòrum','Ask a Question'=>'Fes una pregunta','View All Topics'=>'Mostra tots els temes','by'=>'per','Have a question?'=>'Tens una pregunta?','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'Obtén ajuda directament dels desenvolupadors del connector, suggereix millores o comparteix la teva opinió!','Tip for faster help:'=>'Consell per rebre ajuda més ràpidament:','Include what you tried, what you expected, and what happened. Screenshots help!'=>'Inclou el que has provat, el que esperaves i el que ha passat. Les captures de pantalla ajuden!','Toggle support chat'=>'Activa/desactiva el xat de suport','Ask the community'=>'Pregunta a la comunitat','Close'=>'Tanca','Empty feed response'=>'Resposta buida del canal','Unable to parse feed'=>'No s\'ha pogut analitzar el canal','Just now'=>'Ara mateix','%d hour ago'=>'Fa %d hora' . "\0" . 'Fa %d hores','%d day ago'=>'Fa %d dia' . "\0" . 'Fa %d dies','Source'=>'Font','Srcset'=>'Srcset','Alt attribute'=>'Atribut alt','Title attribute'=>'Atribut title','Anchor link'=>'Enllaç d\'àncora','Placeholder attribute'=>'Atribut placeholder','Submit attribute'=>'Atribut submit','Text'=>'Text','Video Poster'=>'Pòster del vídeo','plural form'=>'forma plural','one'=>'un','few'=>'pocs','many'=>'molts','other'=>'altres','Saved'=>'Desat','Save'=>'Desa','Saving translation...'=>'S\'està desant la traducció...','You have unsaved changes!'=>'Tens canvis sense desar!','Discard changes'=>'Descarta els canvis','Discard All'=>'Descarta-ho tot','Loading Strings...'=>'S\'estan carregant cadenes...','Select string to translate...'=>'Selecciona una cadena per traduir...','Close Editor'=>'Tanca l\'editor','From'=>'De','To'=>'A','Add Media'=>'Afegeix multimèdia','Other languages'=>'Altres idiomes','Context'=>'Context','View Website As'=>'Visualitza el lloc web com a','Available in our Pro Versions'=>'Disponible a les nostres versions Pro','Select or Upload Media'=>'Selecciona o puja multimèdia','Use this media'=>'Utilitza aquest multimèdia','Translate'=>'Tradueix','Translate entire block element'=>'Tradueix tot l\'element de bloc','Split block to translate strings individually'=>'Divideix el bloc per traduir les cadenes individualment','Save changes to translation. Shortcut: CTRL(⌘) + S'=>'Desa els canvis de la traducció. Drecera: CTRL(⌘) + S','Navigate to next string in dropdown list. Shortcut: CTRL(⌘) + ALT + Right Arrow'=>'Navega a la cadena següent de la llista desplegable. Drecera: CTRL(⌘) + ALT + Fletxa dreta','Navigate to previous string in dropdown list. Shortcut: CTRL(⌘) + ALT + Left Arrow'=>'Navega a la cadena anterior de la llista desplegable. Drecera: CTRL(⌘) + ALT + Fletxa esquerra','Discard all changes. Shortcut: CTRL(⌘) + ALT + Z'=>'Descarta tots els canvis. Drecera: CTRL(⌘) + ALT + Z','Discard changes to this text box. To discard changes to all text boxes use shortcut: CTRL(⌘) + ALT + Z'=>'Descarta els canvis d\'aquest quadre de text. Per descartar els canvis de tots els quadres de text, utilitza la drecera: CTRL(⌘) + ALT + Z','Dismiss tooltip'=>'Descarta el consell','Quick Intro'=>'Introducció ràpida','Are you sure you want to split this phrase into smaller parts?'=>'Esteu segur que voleu dividir aquesta frase en parts més petites?','This string is not ready for translation yet. <br>Try again in a moment...'=>'Aquesta cadena encara no està llesta per a la traducció. <br>Torna-ho a provar d\'aquí a un moment...','For this option to work, please update the Browse as other role add-on to the latest version.'=>'Perquè aquesta opció funcioni, actualitzeu el complement Browse as other role a la darrera versió.','To translate slugs, please update the SEO Pack add-on to the latest version.'=>'Per traduir slugs, actualitza el complement SEO Pack a la darrera versió.','You can add a new language from <a href="%s">Settings->TranslatePress</a>'=>'Podeu afegir un idioma nou des de <a href="%s">Configuració->TranslatePress</a>','However, you can still use TranslatePress to <strong style="background: #f5fb9d;">modify gettext strings</strong> available in your page.'=>'Tanmateix, encara pots utilitzar TranslatePress per <strong style="background: #f5fb9d;">modificar cadenes gettext</strong> disponibles a la teva pàgina.','Strings that are user-created cannot be modified, only those from themes and plugins.'=>'Les cadenes creades per l\'usuari no es poden modificar, només les dels temes i els connectors.','Extra Translation Features'=>'Funcions de traducció addicionals','Support for 130+ Extra Languages'=>'Suport per a més de 130 idiomes addicionals','Access to TranslatePress AI'=>'Accés a TranslatePress AI','Translate SEO Title, Description, Slug'=>'Tradueix el títol SEO, la descripció i el slug','Publish only when translation is complete'=>'Publica només quan la traducció estigui completa','Translate by Browsing as User Role'=>'Tradueix navegant com a rol d\'usuari','Different Menu Items for each Language'=>'Elements de menú diferents per a cada idioma','Automatic User Language Detection'=>'Detecció automàtica de l\'idioma de l\'usuari','Upgrade to PRO'=>'Actualitzar a PRO','Upgrade to PRO with our biggest discount of the year!'=>'Actualitza a PRO amb el descompte més gran de l\'any!','This Black Friday, get access to these features and more at a fraction of the costs:'=>'Aquest Black Friday, obtén accés a aquestes funcions i més a una fracció del cost:','No available suggestions'=>'No hi ha suggeriments disponibles','Suggestions from translation memory'=>'Suggeriments de la memòria de traducció','Click to Copy'=>'Fes clic per copiar','Human Translation'=>'Traducció humana','Machine Translation'=>'Traducció automàtica','Text on this page is %s% translated into all languages.'=>'El text d\'aquesta pàgina està traduït en un %s% a tots els idiomes.','%1$s% of text on this page is translated into %2$s.'=>'Un %1$s% del text d\'aquesta pàgina està traduït a %2$s.','This page is %1$s% translated into %2$s.'=>'Aquesta pàgina està traduïda en un %1$s% a %2$s.','The slug that you are trying to edit is present in other slug types:%s%. Editing it will replace each occurrence, regardless of the current type.'=>'El slug que intents editar està present en altres tipus de slug: %s. En editar-lo, es reemplaçarà cada ocurrència, independentment del tipus actual.','Hover any text on the page, click %s,<br> then modify the translation in the sidebar.'=>'Passa el ratolí per sobre de qualsevol text de la pàgina, fes clic a %s,<br> i després modifica la traducció a la barra lateral.','Don\'t forget to Save Translation. Use keyboard shortcut CTRL(⌘) + S'=>'No oblidis desar la traducció. Utilitza la drecera de teclat CTRL(⌘) + S','Switch language to see the translation changes directly on the page.'=>'Canvia l\'idioma per veure els canvis de traducció directament a la pàgina.','Search for any text in this page in the dropdown.'=>'Cerca qualsevol text d\'aquesta pàgina al menú desplegable.','Your %s license has <span class="trp-license-status-emphasized">expired</span>.'=>'La teva llicència %s ha <span class="trp-license-status-emphasized">caducat</span>.','Please renew your license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Si us plau, renova la teva llicència per continuar tenint accés a TranslatePress AI, complements premium, actualitzacions automàtiques i suport.','Renew Now'=>'Renova ara','<strong>This Black Friday, renew your license at a special price</strong> to continue receiving access to product downloads, automatic updates, and support.'=>'<strong>Aquest Black Friday, renova la teva llicència a un preu especial</strong> per continuar tenint accés a les descàrregues de productes, actualitzacions automàtiques i suport.','Get Deal'=>'Aprofita l\'oferta','Your %s license was <span class="trp-license-status-emphasized">refunded</span>.'=>'La teva llicència %s s\'ha <span class="trp-license-status-emphasized">reemborsat</span>.','Please purchase a new license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Si us plau, compra una llicència nova per continuar tenint accés a TranslatePress AI, complements premium, actualitzacions automàtiques i suport.','Purchase a new license'=>'Comprar una llicència nova','Your %s license is <span class="trp-license-status-emphasized">missing or invalid</span>.'=>'La teva llicència %s és <span class="trp-license-status-emphasized">inexistent o no vàlida</span>.','Please enter a valid license to get access to TranslatePress AI, premium addons, automatic updates and support. Need a license key? %1$sPurchase one now%2$s'=>'Si us plau, introdueix una llicència vàlida per accedir a TranslatePress AI, complements premium, actualitzacions automàtiques i suport. Necessites una clau de llicència? %1$sComprar-ne una ara%2$s','Enter a valid license'=>'Introduir una llicència vàlida','Slugs'=>'Slugs','Meta Information'=>'Informació meta','String List'=>'Llista de cadenes','Gettext Strings'=>'Cadenes Gettext','Images'=>'Imatges','Videos'=>'Vídeos','Audios'=>'Àudios','Dynamically Added Strings'=>'Cadenes afegides dinàmicament','Translation Editor'=>'Editor de traduccions','Edit translations by visually selecting them on each site page'=>'Editar les traduccions seleccionant-les visualment a cada pàgina del lloc','String Translation'=>'Traducció de cadenes','Edit url slug translations, plugins and theme translation (emails, forms etc.)'=>'Edita les traduccions de slugs d\'URL, la traducció de connectors i temes (correus electrònics, formularis, etc.)','Current User'=>'Usuari actual','Logged Out'=>'Desconnectat','Translate Page'=>'Traduir la pàgina','Add a New Language'=>'Afegir un nou idioma','Get a Free AI License'=>'Obtén una llicència d\'IA gratuïta','Your License is Invalid'=>'La llicència no és vàlida','Get More AI Words (%d left)'=>'Obtén més paraules d\'IA (queden %d)','Opens post in the translation editor. Post must be saved as draft or published beforehand.'=>'Obre l\'entrada a l\'editor de traducció. L\'entrada ha d\'haver estat desada com a esborrany o publicada prèviament.','Security check'=>'Comprovació de seguretat','<strong>Warning:</strong> Some strings have possibly incorrectly encoded characters. This may result in breaking the queries, rendering the page untranslated in live mode. Consider revising the following strings or their method of outputting.'=>'<strong>Avís:</strong> Algunes cadenes poden tenir caràcters codificats incorrectament. Això pot provocar errors en les consultes i fer que la pàgina no es tradueixi en mode en viu. Revisa les cadenes següents o el seu mètode de sortida.','TranslatePress data update'=>'Actualització de dades de TranslatePress','We need to update your translations database to the latest version.'=>'Hem d\'actualitzar la base de dades de traduccions a l\'última versió.','Updating will allow editing translations of localized text from plugins and theme. Existing translation will still work as expected.'=>'L\'actualització permetrà editar les traduccions del text localitzat de plugins i del tema. La traducció existent continuarà funcionant com s\'espera.','IMPORTANT: It is strongly recommended to first backup the database!
Are you sure you want to continue?'=>'IMPORTANT: Es recomana fermament fer primer una còpia de seguretat de la base de dades!\\nN\'estàs segur que vols continuar?','Run the updater'=>'Executa l\'actualitzador','Updating will allow editing translations of slugs. Existing translation will still work as expected.'=>'L\'actualització permetrà editar les traduccions dels slugs. La traducció existent continuarà funcionant com s\'espera.','Please activate the SEO Addon from <br/>WordPress -> Settings -> TranslatePress -> Addons section'=>'Si us plau, activa el complement SEO des de<br/>WordPress -> Configuració -> TranslatePress -> secció de complements','Go to Addons'=>'Ves a complements','The SEO Pack add-on allows translation of all the URL slugs:'=>'El complement SEO Pack permet traduir tots els slugs d\'URL:','Taxonomy slugs'=>'Slugs de taxonomia','Term slugs'=>'Slugs de termes','Post slugs (this includes pages and custom post types)'=>'Slugs d\'entrades (això inclou pàgines i tipus d\'entrada personalitzats)','Post type base slugs'=>'Slugs base de tipus d\'entrada','WooCommerce slugs'=>'Slugs de WooCommerce','The SEO Pack add-on is available with ALL premium versions of the plugin.'=>'El complement SEO Pack està disponible amb TOTES les versions premium del connector.','Upgrade to Pro'=>'Actualitza a Pro','Description'=>'Descripció','Article Section'=>'Secció de l\'article','Article Tag'=>'Etiqueta de l\'article','OG Title'=>'Títol OG','OG Site Name'=>'Nom del lloc OG','OG Description'=>'Descripció OG','OG Image Alt'=>'Text alternatiu de la imatge OG','Twitter Title'=>'Títol de Twitter','Twitter Description'=>'Descripció de Twitter','Twitter Image Alt'=>'Text alternatiu de la imatge de Twitter','Page Title'=>'Títol de la pàgina','Dublin Core Title'=>'Títol de Dublin Core','Dublin Core Description'=>'Descripció de Dublin Core','OG Image'=>'Imatge OG','OG Image Secure URL'=>'URL segura de la imatge OG','Twitter Image'=>'Imatge de Twitter','Removing cdata dictionary strings for language %s...'=>'S\'estan eliminant les cadenes del diccionari cdata per a l\'idioma %s...','Removing untranslated dictionary links for language %s...'=>'S\'estan eliminant els enllaços no traduïts del diccionari per a l\'idioma %s...','Removing duplicated gettext strings for language %s...'=>'S\'estan eliminant les cadenes gettext duplicades per a l\'idioma %s...','Removing duplicated dictionary strings for language %s...'=>'S\'estan eliminant les cadenes del diccionari duplicades per a l\'idioma %s...','Removing untranslated dictionary strings where translation is available for language %s...'=>'S\'estan eliminant les cadenes del diccionari sense traduir per a les quals hi ha traducció disponible per a l\'idioma %s...','Inserting original strings for language %s...'=>'S\'estan inserint les cadenes originals per a l\'idioma %s...','Cleaning original strings table for language %s...'=>'S\'està netejant la taula de cadenes originals per a l\'idioma %s...','Updating original string ids for language %s...'=>'S\'estan actualitzant els ID de les cadenes originals per a l\'idioma %s...','Regenerating original meta table for language %s...'=>'S\'està regenerant la taula de metadades originals per a l\'idioma %s...','Cleaning original meta table for language %s...'=>'S\'està netejant la taula de metadades originals per a l\'idioma %s...','Replacing original id NULL with value for language %s...'=>'S\'està substituint l\'identificador original NULL per un valor per a l\'idioma %s...','Inserting gettext original strings for language %s...'=>'S\'estan inserint les cadenes originals gettext per a l\'idioma %s...','Cleaning gettext original strings table for language %s...'=>'S\'està netejant la taula de cadenes originals gettext per a l\'idioma %s...','Updating gettext original string ids for language %s...'=>'S\'estan actualitzant els ID de les cadenes originals gettext per a l\'idioma %s...','Migrating taxonomy and post type base slugs to new table structure...'=>'S\'estan migrant els slugs de taxonomia i els slugs base de tipus d\'entrada a la nova estructura de taules...','Migrating post slugs to new table structure for language %s...'=>'S\'estan migrant els slugs d\'entrades a la nova estructura de taules per a l\'idioma %s...','Migrating term slugs to new table structure for language %s...'=>'S\'estan migrant els slugs de termes a la nova estructura de taules per a l\'idioma %s...','Finishing up...'=>'Finalitzant...','Database optimization did not complete successfully. We recommend restoring the original database or <a href="%s" >trying again.</a>'=>'L\'optimització de la base de dades no s\'ha completat correctament. Recomanem restaurar la base de dades original o <a href="%s" >tornar-ho a intentar.</a>','Update aborted! Your user account doesn\'t have the capability to perform database updates.'=>'S\'ha avortat l\'actualització! El vostre compte d\'usuari no té la capacitat per a realitzar actualitzacions de la base de dades.','Update aborted! Invalid nonce.'=>'S\'ha avortat l\'actualització! Nonce no vàlid.','Update aborted! Incorrect action.'=>'S\'ha avortat l\'actualització! Acció incorrecta.','Update aborted! Incorrect language code.'=>'S\'ha interromput l\'actualització! El codi d\'idioma és incorrecte.','Updating database to version %s+'=>'S\'està actualitzant la base de dades a la versió %s+','Processing table for language %s...'=>'S\'està processant la taula per a l\'idioma %s...','Back to TranslatePress Settings'=>'Torna a la configuració de TranslatePress','Successfully updated database!'=>'S\'ha actualitzat la base de dades correctament!',' done.'=>' fet.','All individual TranslatePress add-on plugins <a href="%1$s" target="_blank">have been discontinued</a> and are now included in the premium Personal, Business and Developer versions of TranslatePress. Please log into your <a href="%2$s" target="_blank">account page</a>, download the new premium version and install it. Your individual addons settings will be ported over.'=>'Tots els plugins complementaris individuals de TranslatePress <a href="%1$s" target="_blank">han estat discontinuats</a> i ara s\'inclouen a les versions premium Personal, Business i Developer de TranslatePress. Inicieu sessió a la vostra <a href="%2$s" target="_blank">pàgina de compte</a>, baixeu la nova versió premium i instal·leu-la. La configuració dels vostres complements individuals es transferirà.','Brand-new Language Switcher Settings are here!'=>'La configuració del selector d\'idioma completament nova ja és aquí!','Explore pre-made templates, switch colors, flag styles, spacing, layouts & more. Use the live preview to perfect your switcher in seconds.'=>'Exploreu plantilles predefinides, canvieu colors, estils de banderes, espaiats, dissenys i molt més. Utilitzeu la vista prèvia en directe per a perfeccionar el vostre selector en segons.','Start customizing'=>'Comença a personalitzar','Read documentation'=>'Consulta la documentació','TranslatePress'=>'TranslatePress','<strong>TranslatePress</strong> requires <strong><a href="http://php.net/manual/en/book.mbstring.php">Multibyte String PHP library</a></strong>. Please contact your server administrator to install it on your server.'=>'<strong>TranslatePress</strong> requereix <strong><a href="http://php.net/manual/en/book.mbstring.php">la biblioteca de cadenes multibyte de PHP</a></strong>. Si us plau, contacta amb l\'administrador del servidor perquè la instal·li al teu servidor.','Detected long query limitation on WPEngine hosting. Some large pages may appear untranslated. You can remove limitation by adding the following to your site’s wp-config.php: define( \'WPE_GOVERNOR\', false ); '=>'S\'ha detectat una limitació de consultes llargues a l\'allotjament WPEngine. Algunes pàgines grans poden aparèixer sense traduir. Podeu eliminar la limitació afegint el següent al fitxer wp-config.php del vostre lloc: define( \'WPE_GOVERNOR\', false ); ','Custom Language Flag'=>'Bandera d\'idioma personalitzada','The Language code of the added custom language cannot be empty.'=>'El codi d\'idioma de l\'idioma personalitzat afegit no pot estar buit.','The Language code of the added custom language is invalid.'=>'El codi d\'idioma de l\'idioma personalitzat afegit no és vàlid.','The Automatic Translation Code of the added custom language is invalid.'=>'El codi de traducció automàtica de l\'idioma personalitzat afegit no és vàlid.','TranslatePress Add-ons'=>'Complements de TranslatePress','You must first purchase this version to have access to the addon %1$shere%2$s'=>'Heu de comprar primer aquesta versió per tenir accés al complement %1$saquí%2$s','Please %1$senter your license%2$s key first, to activate this addon.'=>'Si us plau, %1$sintroduïu la clau de llicència%2$s primer per activar aquest complement.','You need an active license to have access to the addon. Renew or purchase a new one %1$shere%2$s.'=>'Necessiteu una llicència activa per tenir accés al complement. Renoveu-la o compreu-ne una de nova %1$saquí%2$s.','Advanced Add-ons'=>'Complements avançats','These addons extend your translation plugin and are available in the Developer, Business and Personal plans.'=>'Aquests complements amplien el vostre connector de traducció i estan disponibles als plans Developer, Business i Personal.','SEO Pack'=>'SEO Pack','SEO Pack (Legacy)'=>'SEO Pack (antic)','SEO support for page slug, page title, description and facebook and twitter social graph information. The HTML lang attribute is properly set.'=>'Suport SEO per al slug de pàgina, el títol de pàgina, la descripció i la informació del gràfic social de Facebook i Twitter. L\'atribut lang de l\'HTML s\'estableix correctament.','Multiple Languages'=>'Múltiples idiomes','Add as many languages as you need for your project to go global. Publish your language only when all your translations are done.'=>'Afegiu tants idiomes com necessiteu perquè el vostre projecte arribi a tot el món. Publiqueu l\'idioma només quan totes les traduccions estiguin fetes.','Pro Add-ons'=>'Complements Pro','These addons extend your translation plugin and are available in the Business and Developer plans.'=>'Aquests complements amplien el vostre connector de traducció i estan disponibles als plans Business i Developer.','DeepL Automatic Translation'=>'Traducció automàtica DeepL','Automatically translate your website through the DeepL API.'=>'Tradueix automàticament el vostre lloc web mitjançant l\'API DeepL.','Prompts visitors to switch to their preferred language based on their browser settings or IP address and remembers the last visited language.'=>'Suggerix als visitants que canviïn al seu idioma preferit segons la configuració del navegador o l\'adreça IP i recorda l\'últim idioma visitat.','Translator Accounts'=>'Comptes de traductor','Create translator accounts for new users or allow existing users that are not administrators to translate your website.'=>'Creeu comptes de traductor per a usuaris nous o permeteu que els usuaris existents que no són administradors tradueixin el vostre lloc web.','Browse As User Role'=>'Navegació com a rol d\'usuari','Navigate your website just like a particular user role would. Really useful for dynamic content or hidden content that appears for particular users.'=>'Navegueu pel vostre lloc web tal com ho faria un rol d\'usuari concret. Molt útil per a contingut dinàmic o contingut ocult que apareix per a usuaris concrets.','Navigation Based on Language'=>'Navegació basada en l\'idioma','Configure different menu items for different languages.'=>'Configureu diferents elements de menú per a diferents idiomes.','Different Domain per Language'=>'Domini diferent per idioma','Connect separate domains or subdomains to each of your translated versions. Strengthen your brand’s local identity and boost SEO performance for every language you support.'=>'Connecteu dominis o subdominis separats a cadascuna de les vostres versions traduïdes. Reforceu la identitat local de la vostra marca i milloreu el rendiment SEO per a cada idioma que admeteu.','Recommended Plugins'=>'Plugins recomanats','A short list of plugins you can use to extend your website.'=>'Una llista breu de plugins que podeu utilitzar per ampliar el vostre lloc web.','Profile Builder'=>'Profile Builder','Capture more user information on the registration form with the help of Profile Builder\'s custom user profile fields and/or add an Email Confirmation process to verify your customers accounts.'=>'Captureu més informació d\'usuari al formulari de registre amb l\'ajuda dels camps de perfil d\'usuari personalitzats de Profile Builder i/o afegiu un procés de confirmació per correu electrònic per verificar els comptes dels vostres clients.','Paid Member Subscriptions'=>'Paid Member Subscriptions','Accept user payments, create subscription plans and restrict content on your membership site.'=>'Accepteu pagaments d\'usuaris, creeu plans de subscripció i restringiu el contingut al vostre lloc de membres.','WP Webhooks Automator'=>'WP Webhooks Automator','Create no-code automations and workflows on your WordPress site. Easily connect your plugins, sites and apps together.'=>'Creeu automatitzacions i fluxos de treball sense codi al vostre lloc WordPress. Connecteu fàcilment els vostres plugins, llocs i aplicacions entre si.','Save Changes'=>'Desa els canvis','TranslatePress Errors'=>'Errors de TranslatePress','There are no logged errors.'=>'No hi ha errors registrats.','Change language'=>'Canvia l\'idioma','Website language selector'=>'Selector d\'idioma del lloc web','WordPress Translation Plugin'=>'Plugin de traducció per a WordPress','Available languages'=>'Idiomes disponibles','Language Switcher update notice'=>'Avís d\'actualització del selector d\'idioma','Legacy language switcher is currently enabled'=>'El selector d\'idioma heretat està activat actualment','We’ve upgraded the switcher for richer customization and a better user experience.<br>In order to use the new configurator, turn off <strong>Load legacy language switcher</strong>.'=>'Hem actualitzat el selector per a una personalització més rica i una millor experiència d\'usuari.<br>Per utilitzar el nou configurador, desactiveu <strong>Carregar el selector d\'idioma heretat</strong>.','Note: You can switch back anytime from <strong>Advanced Settings → <a href="%s">Troubleshooting</a></strong>.'=>'Nota: Pots tornar en qualsevol moment des de <strong>Configuració avançada → <a href="%s">Resolució de problemes</a></strong>.','Enable the new switcher'=>'Activa el commutador nou','Your License Key is valid.'=>'La clau de llicència és vàlida.','Your License Key is invalid.'=>'La clau de llicència no és vàlida.','Your License has expired.'=>'La llicència ha caducat.','Deactivate License'=>'Desactiva la llicència','Add a license key'=>'Afegeix una clau de llicència','License Key'=>'Clau de llicència','Manage your license in your %1$s.'=>'Gestiona la teva llicència a la teva %1$s.','Account Page'=>'Pàgina del compte','Don’t have a TranslatePress AI License Key?'=>'No tens una clau de llicència de TranslatePress AI?','You can get one for %1$sfree%2$s, by creating a free account. It includes:'=>'Pots obtenir-ne una %1$sgratuïtament%2$s, creant un compte gratuït. Inclou:','Access to TranslatePress AI for instant automatic translations'=>'Accés a TranslatePress AI per a traduccions automàtiques instantànies','2000 AI words to translate automatically'=>'2000 paraules d\'IA per traduir automàticament','Get a free License Today'=>'Obtén una llicència gratuïta avui','Debug Information'=>'Informació de depuració','Debug Data for License Checking'=>'Dades de depuració per a la comprovació de la llicència','Debug Data for License Activation'=>'Dades de depuració per a l\'activació de la llicència','Get more AI words and unlock all features with TranslatePress Pro.'=>'Obtén més paraules d\'IA i desbloqueja totes les funcions amb TranslatePress Pro.','Upgrade now ↗'=>'Actualitza ara ↗','Already purchased a Premium version?'=>'Ja has comprat una versió Premium?','Go to your %1$s'=>'Ves al teu %1$s','TranslatePress.com Account'=>'Compte de TranslatePress.com','Download & Install the Pro plugin'=>'Descarrega i instal·la el connector Pro','Learn More'=>'Més informació','Get a translation volume estimate with a detailed breakdown per page'=>'Obtén una estimació del volum de traducció amb un desglossament detallat per pàgina','Find how many translatable words are on your website'=>'Troba quantes paraules traduïbles hi ha al teu lloc web','Enable Automatic Translation'=>'Habilita la traducció automàtica','To use <strong>DeepL</strong> for automatic translation, activate this Pro add-on from the <a href="%1$s" target="_self" title="%2$s">%2$s</a>.'=>'Per utilitzar <strong>DeepL</strong> per a la traducció automàtica, activa aquest complement Pro des de <a href="%1$s" target="_self" title="%2$s">%2$s</a>.','<strong>DeepL</strong> automatic translation is available as a <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.'=>'La traducció automàtica de <strong>DeepL</strong> està disponible com a <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.','By upgrading you\'ll get access to all paid add-ons, premium support and help fund the future development of TranslatePress.'=>'Si actualitzes, tindràs accés a tots els complements de pagament, suport premium i ajudaràs a finançar el desenvolupament futur de TranslatePress.','Please note that DeepL API usage is paid separately. See <a href="https://www.deepl.com/pro.html#developer">DeepL pricing information</a>.'=>'Tingues en compte que l\'ús de l\'API de DeepL es paga a part. Consulta la <a href="https://www.deepl.com/pro.html#developer">informació de preus de DeepL</a>.','TranslatePress Pro Add-ons'=>'Complements de TranslatePress Pro','Test API credentials'=>'Prova les credencials de l\'API','Check if the selected translation engine is configured correctly.'=>'Comprova si el motor de traducció seleccionat està configurat correctament.','Alternative Engines'=>'Motors alternatius','Switch to TranslatePress AI'=>'Canvia a TranslatePress AI','Integrate machine translation directly with your WordPress website.'=>'Integra la traducció automàtica directament amb el teu lloc web de WordPress.','More info'=>'Més informació','Choose which engine you want to use in order to %1$s automatically translate your website.'=>'Tria quin motor vols fer servir per tal de %1$s traduir automàticament el teu lloc web.','Automatic Translation Settings'=>'Configuració de la traducció automàtica','AI Words Low Notification'=>'Notificació de nivell baix de paraules d\'IA','Receive an email notification when your TranslatePress AI word count drops below the specified threshold.'=>'Rebreu una notificació per correu electrònic quan el recompte de paraules del TranslatePress AI baixi per sota del llindar especificat.','This feature is only available when using the TranslatePress AI translation engine.'=>'Aquesta funció només està disponible quan s\'utilitza el motor de traducció TranslatePress AI.','Notification Email'=>'Correu electrònic de notificació','The email address where the low AI words notification will be sent.'=>'L\'adreça de correu electrònic on s\'enviarà la notificació de nivell baix de paraules d\'IA.','Word Threshold'=>'Llindar de paraules','words'=>'paraules','You will be notified when remaining AI words drop below this number.'=>'Rebreu una notificació quan les paraules d\'IA restants baixin per sota d\'aquest nombre.','Automatically Translate Slugs'=>'Traducció automàtica de slugs','Generate automatic translations of slugs for posts, pages and Custom Post Types.<br/>The slugs will be automatically translated starting with the second refresh of each page.'=>'Genera traduccions automàtiques de slugs per a entrades, pàgines i tipus de contingut personalitzats.<br/>Els slugs es traduiran automàticament a partir de la segona actualització de cada pàgina.','This feature is only available in the paid version. Upgrade TranslatePress and unlock more premium features.'=>'Aquesta funció només està disponible a la versió de pagament. Actualitzeu TranslatePress i desbloquegeu més funcions premium.','Requires <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack Add-on</a> to be installed and activated.'=>'Requereix que el complement <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack</a> estigui instal·lat i activat.','Upgrade now'=>'Actualitza ara','Block Crawlers'=>'Bloqueig de rastrejadors','Block crawlers from triggering automatic translations on your website.<br>This will not prevent crawlers from accessing this site\'s pages.'=>'Bloqueja els rastrejadors perquè no activin traduccions automàtiques al vostre lloc web.<br>Això no impedirà que els rastrejadors accedeixin a les pàgines d\'aquest lloc.','Limit machine translation / characters per day'=>'Limitar la traducció automàtica / caràcters per dia','Add a limit to the number of automatically translated characters so you can better budget your project.'=>'Afegir un límit al nombre de caràcters traduïts automàticament per poder gestionar millor el pressupost del projecte.','characters per day'=>'caràcters per dia','Today\'s Character Count: '=>'Recompte de caràcters d\'avui: ','Log machine translation queries.'=>'Registra les consultes de traducció automàtica.','Only enable for testing purposes. Can impact performance.<br>All records are stored in the wp_trp_machine_translation_log database table. Use a plugin like <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> to browse the logs or directly from your database manager (PHPMyAdmin, etc.)'=>'Només activeu-ho amb finalitats de prova. Pot afectar el rendiment.<br>Tots els registres s\'emmagatzemen a la taula de la base de dades wp_trp_machine_translation_log. Utilitzeu un connector com <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> per a consultar els registres o directament des del vostre gestor de bases de dades (PHPMyAdmin, etc.)','Test API Credentials'=>'Prova les credencials de l\'API','HTTP Referrer: '=>'Referent HTTP: ','Use this HTTP Referrer if the API lets you restrict key usage from its Dashboard.'=>'Utilitzeu aquest referent HTTP si l\'API us permet restringir l\'ús de la clau des del seu tauler.','Response'=>'Resposta','Response Body'=>'Cos de la resposta','Entire Response From wp_remote_get():'=>'Resposta completa de wp_remote_get():','All Languages'=>'Tots els idiomes','Select the languages you wish to make your website available in.'=>'Seleccioneu els idiomes en què voleu que el vostre lloc web estigui disponible.','Formality'=>'Formalitat','Code'=>'Codi','Slug'=>'Slug','Default'=>'Per defecte','Formal'=>'Formal','Informal'=>'Informal','Language'=>'Idioma','This language does not support formality. '=>'Aquest idioma no admet la formalitat. ','Are you sure you want to remove this language?'=>'Esteu segur que voleu eliminar aquest idioma?','Custom Languages'=>'Idiomes personalitzats','To Add more languages activate the Multiple Languages Addon'=>'Per afegir més idiomes, activa el complement de múltiples idiomes','You need an active license to add more languages. Verify in your %1$saccount%2$s that your license is valid'=>'Necessites una llicència activa per afegir més idiomes. Verifica al teu %1$scompte%2$s que la llicència és vàlida.','Please %1$senter your license%2$s key first to add more languages.'=>'Si us plau, %1$sintrodueix la clau de la teva llicència%2$s primer per afegir més idiomes.','Adding more than two languages is a paid feature. Upgrade TranslatePress and unlock more premium features.'=>'Afegir més de dos idiomes és una funció de pagament. Actualitza TranslatePress i desbloqueja més funcions premium.','Website Languages'=>'Idiomes del lloc web','Default Language'=>'Idioma per defecte','Select the language your content is written in.'=>'Selecciona l\'idioma en què està escrit el contingut.','WARNING. Changing the default language will invalidate existing translations.'=>'ADVERTÈNCIA. Canviar l\'idioma per defecte invalidarà les traduccions existents.','Even changing from en_US to en_GB, because they are treated as two different languages.'=>'Fins i tot canviar d\'en_US a en_GB, perquè es tracten com dos idiomes diferents.','In most cases changing the default flag is all it is needed: '=>'En la majoria de casos, canviar la bandera per defecte és tot el que es necessita: ','replace the default flag'=>'substitueix la bandera per defecte','Re-run Setup Wizard'=>'Torna a executar l\'assistent de configuració','The Setup wizard allows you to quickly setup TranslatePress. You can initiate it at any time.'=>'L\'assistent de configuració et permet configurar TranslatePress ràpidament. El pots iniciar en qualsevol moment.','Language Settings'=>'Configuració d\'idioma','Use Native language name'=>'Utilitza el nom de l\'idioma en la seva llengua','Check if you want to display languages in their native names. Otherwise, languages will be displayed in English.'=>'Marca aquesta opció si vols mostrar els idiomes amb els seus noms natius. En cas contrari, es mostraran en anglès.','Use a subdirectory for the default language'=>'Utilitza un subdirectori per a l\'idioma per defecte','Check if you want to add the subdirectory in the URL for the default language.</br>By checking this option, the default language seen by website visitors will become the first one in the "All Languages" list.'=>'Marca aquesta opció si vols afegir el subdirectori a l\'URL per a l\'idioma per defecte.<br/>En marcar aquesta opció, l\'idioma per defecte que veuran els visitants del lloc web serà el primer de la llista «Tots els idiomes».','Force language in custom links'=>'Força l\'idioma en els enllaços personalitzats','Select Yes if you want to force custom links without language encoding to keep the currently selected language.'=>'Selecciona Sí si vols forçar els enllaços personalitzats sense codificació d\'idioma per mantenir l\'idioma actualment seleccionat.','Shortcode '=>'Shortcode ','Use shortcode on any page or widget.'=>'Fes servir el shortcode a qualsevol pàgina o giny.','You can also add the <a href="%s" title="Language Switcher Block Documentation">Language Switcher Block</a> in the WP Gutenberg Editor.'=>'També pots afegir el <a href="%s" title="Language Switcher Block Documentation">Bloc de selector d\'idioma</a> a l\'editor Gutenberg de WP.','Menu item'=>'Element de menú','Go to  %1$s Appearance -> Menus%2$s to add languages to the Language Switcher in any menu.'=>'Ves a  %1$s Aparença -> Menús%2$s per afegir idiomes al commutador d\'idioma de qualsevol menú.','Learn more in our documentation.'=>'Més informació a la nostra documentació.','Floating language selection'=>'Selecció d\'idioma flotant','Add a floating dropdown that follows the user on every page.'=>'Afegeix un desplegable flotant que segueix l\'usuari a cada pàgina.','Show "Powered by TranslatePress"'=>'Mostra "Powered by TranslatePress"','Show the small "Powered by TranslatePress" label in the floater language switcher.'=>'Mostra l\'etiqueta petita "Powered by TranslatePress" al commutador d\'idioma flotant.','5 Days to Better Multilingual Websites'=>'5 dies per millorar els llocs web multilingües','%sJoin our FREE & EXCLUSIVE onboarding course%s and learn how to grow your multilingual traffic, reach international markets, and save time & money while getting the most out of TranslatePress!'=>'%sUneix-te al nostre curs d\'integració GRATUÏT & EXCLUSIU%s i aprèn a augmentar el teu trànsit multilingüe, arribar a mercats internacionals i estalviar temps & diners mentre treus el màxim profit de TranslatePress!','Invalid email address'=>'Adreça de correu electrònic no vàlida','Your email'=>'El teu correu electrònic','Sign me up!'=>'Apunta\'m!','Sign up with your email address and receive a 5-part email guide to help you maximize the power of TranslatePress.'=>'Apunta\'t amb la teva adreça de correu electrònic i rep una guia per correu electrònic en 5 parts per ajudar-te a treure el màxim profit de TranslatePress.','Dismiss email course notification'=>'Descarta la notificació del curs per correu electrònic','Hey %s,<br>Never miss an important update - opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Hola %s,<br>No et perdis mai una actualització important: activa les notificacions d\'actualitzacions de seguretat i funcions, i el seguiment diagnòstic no sensible.','Allow & Continue'=>'Permet & continua','Skip'=>'Omet','This will allow TranslatePress to:'=>'Això permetrà a TranslatePress:','Your profile overview'=>'Visió general del perfil','Name and email address'=>'Nom i adreça de correu electrònic','Admin Notices'=>'Avisos d\'administració','Updates, announcements, marketing, no spam'=>'Actualitzacions, anuncis, màrqueting, sense spam','Plugin status & settings'=>'Estat i configuració del connector','Active, Deactivated, installed version and settings'=>'Actiu, desactivat, versió instal·lada i configuració','Privacy Policy'=>'Política de privadesa','Terms of Service'=>'Condicions del servei','Support'=>'Suport','Documentation'=>'Documentació','Add Extra AI Words'=>'Afegeix paraules addicionals d\'IA','Optimize TranslatePress database tables'=>'Optimitza les taules de la base de dades de TranslatePress','<strong>IMPORTANT NOTE:</strong> Before performing this action it is strongly recommended to first backup the database.'=>'<strong>NOTA IMPORTANT:</strong> Abans de realitzar aquesta acció, es recomana fermament fer primer una còpia de seguretat de la base de dades.','IMPORTANT: It is strongly recommended to first backup the database!! Are you sure you want to continue?'=>'IMPORTANT: Es recomana fermament fer primer una còpia de seguretat de la base de dades!! Esteu segur que voleu continuar?','Operations to perform'=>'Operacions a realitzar','Remove CDATA for original and dictionary strings'=>'Elimina el CDATA de les cadenes originals i de diccionari','Removes CDATA from trp_original_strings and trp_dictionary_* tables.<br>This type of content should not be detected by TranslatePress. It might have been introduced in the database in older versions of the plugin.'=>'Elimina el CDATA de les taules trp_original_strings i trp_dictionary_*.<br>Aquest tipus de contingut no hauria de ser detectat per TranslatePress. Podria haver estat introduït a la base de dades en versions antigues del connector.','Remove untranslated links from dictionary tables'=>'Elimina els enllaços no traduïts de les taules del diccionari','Removes untranslated links and images from all trp_dictionary_* tables. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Elimina els enllaços i les imatges no traduïts de totes les taules trp_dictionary_*. Aquestes taules contenen traduccions de cadenes introduïdes per l\'usuari, com ara contingut d\'entrada, títol d\'entrada, menús, etc.','Remove duplicate rows for gettext strings'=>'Elimina les files duplicades de les cadenes Gettext','Cleans up all trp_gettext_* tables of duplicate rows. These tables contain translations for themes and plugin strings.'=>'Neteja les taules trp_gettext_* de files duplicades. Aquestes taules contenen traduccions de cadenes de temes i connectors.','Remove duplicate rows for dictionary strings'=>'Elimina les files duplicades de les cadenes de diccionari','Cleans up all trp_dictionary_* tables of duplicate rows. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Neteja les taules trp_dictionary_* de files duplicades. Aquestes taules contenen traduccions de cadenes introduïdes per l\'usuari, com ara contingut d\'entrada, títol d\'entrada, menús, etc.','Remove duplicate rows for original dictionary strings'=>'Elimina les files duplicades de les cadenes originals de diccionari','Cleans up all trp_original_strings table of duplicate rows. This table contains strings in the default language, without any translation.<br>The trp_original_meta table, which contains meta information that refers to the post parent’s ID, is also regenerated.<br>Such duplicates can appear in exceptional situations of unexpected behavior.'=>'Neteja la taula trp_original_strings de files duplicades. Aquesta taula conté cadenes en l\'idioma per defecte, sense cap traducció.<br>La taula trp_original_meta, que conté informació de metadades que fa referència a l\'ID de la publicació pare, també es regenera.<br>Aquests duplicats poden aparèixer en situacions excepcionals de comportament inesperat.','Replace gettext strings that have original ID NULL with the correct original IDs'=>'Substitueix les cadenes Gettext que tenen l\'ID original NULL pels IDs originals correctes','Fixes an edge case issue where some gettext strings have the original ID incorrectly set to NULL, causing problems in the Translation Editor.<br>This operation corrects the original IDs in the trp_gettext_* tables.<br>Only check this option if you encountered an issue in the Translation Editor where clicking the green pencil did not bring up the gettext string for translation in the left sidebar.<br>Otherwise, please leave this option unchecked because it\'s an intensive operation.'=>'Corregeix un problema de cas límit on algunes cadenes Gettext tenen l\'ID original establert incorrectament a NULL, provocant problemes a l\'Editor de traducció.<br>Aquesta operació corregeix els IDs originals de les taules trp_gettext_*.<br>Marca aquesta opció només si has trobat un problema a l\'Editor de traducció on fer clic al llapis verd no mostrava la cadena Gettext per traduir a la barra lateral esquerra.<br>En cas contrari, deixa aquesta opció desmarcada, ja que és una operació intensiva.','Optimize Database'=>'Optimitza la base de dades','TranslatePress Database Updater'=>'TranslatePress Database Updater','Updating TranslatePress tables. Please leave this window open.'=>'S\'estan actualitzant les taules de TranslatePress. Deixeu aquesta finestra oberta.','The inactive languages will still be visible and active for the admin. For other users they won\'t be visible in the language switchers and won\'t be accessible either.'=>'Els idiomes inactius encara seran visibles i actius per a l\'administrador. Per a altres usuaris no seran visibles als selectors d\'idioma i tampoc no seran accessibles.','unknown'=>'desconegut','<strong>Extra Languages add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'El complement <strong>Extra Languages</strong> requereix la versió %1$s o superior de TranslatePress. Actualment esteu utilitzant la versió %2$s. Actualitzeu TranslatePress per activar aquesta funcionalitat.','Automatic and manual slug translation changes performed when <strong>TranslatePress - Multilingual</strong> 2.8.4 was active had to be removed because of some issues with that version. All slug translations from before that version are now in use. Thank you for understanding!'=>'Els canvis de traducció de slugs automàtics i manuals realitzats mentre <strong>TranslatePress - Multilingual</strong> 2.8.4 estava actiu s\'han hagut de suprimir a causa d\'alguns problemes d\'aquella versió. Totes les traduccions de slugs anteriors a aquella versió estan ara en ús. Gràcies per la comprensió!','If you absolutely need them, the removed translations can be found in tables trp_slug_original_obsolete and trp_slug_translation_obsolete.'=>'Si les necessiteu absolutament, les traduccions eliminades es troben a les taules trp_slug_original_obsolete i trp_slug_translation_obsolete.','View Docs'=>'Veure la documentació','Assign different domains or subdomains to each language. When visitors access these domains, TranslatePress loads the appropriate language translation directly without redirecting.'=>'Assigneu diferents dominis o subdominis a cada idioma. Quan els visitants accedeixen a aquests dominis, TranslatePress carrega directament la traducció a l\'idioma adequat sense redirigir.','Example: %1$s for English, %2$s for Spanish, %3$s for French.'=>'Exemple: %1$s per a l\'anglès, %2$s per a l\'espanyol, %3$s per al francès.','Before enabling:'=>'Abans d\'activar:','Ensure your domains are registered, pointed to your server, and have SSL certificates configured.'=>'Assegureu-vos que els vostres dominis estan registrats, apuntats al vostre servidor i tenen els certificats SSL configurats.','Domain'=>'Domini','Map this language to a different domain or sub-domain.'=>'Assigna aquest idioma a un domini o subdomini diferent.','https://example.com'=>'https://example.com','Prefill with current domain'=>'Omple amb el domini actual','Check DNS'=>'Comprova el DNS','Checking DNS...'=>'S\'està comprovant el DNS...','DNS is correctly configured!'=>'El DNS està configurat correctament!','DNS check failed. Please verify your domain configuration.'=>'La comprovació del DNS ha fallat. Si us plau, comproveu la configuració del domini.','This domain is already assigned to another language.'=>'Aquest domini ja està assignat a un altre idioma.','<strong>Different Domain per Language add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Different Domain per Language add-on</strong> requereix la versió %1$s o superior de TranslatePress. Actualment esteu utilitzant la versió %2$s. Actualitzeu TranslatePress per habilitar aquesta funcionalitat.','Note: This option is disabled when Different Domain for Language addon is active.'=>'Nota: Aquesta opció està desactivada quan Different Domain for Language addon està actiu.','Different Domain per Language: Domain is required when domain mapping is enabled. The toggle has been disabled for languages with empty domains.'=>'Different Domain per Language: El domini és obligatori quan l\'assignació de dominis està activada. S\'ha desactivat l\'interruptor per als idiomes amb dominis buits.','Different Domain per Language: The same domain cannot be assigned to multiple languages. The toggle has been disabled for duplicate domains.'=>'Different Domain per Language: El mateix domini no es pot assignar a diversos idiomes. S\'ha desactivat l\'interruptor per als dominis duplicats.','Different Domain per Language: A language domain cannot be the same as the main site URL. The toggle has been disabled for the matching domain.'=>'Different Domain per Language: El domini d\'un idioma no pot ser el mateix que l\'URL del lloc principal. S\'ha desactivat l\'interruptor per al domini coincident.','Please enter a domain.'=>'Si us plau, introduïu un domini.','Invalid domain format.'=>'Format de domini no vàlid.','Could not reach domain: %s'=>'No s\'ha pogut accedir al domini: %s','Domain returned HTTP status %d.'=>'El domini ha retornat l\'estat HTTP %d.','Domain is reachable!'=>'El domini és accessible!','Limit this menu item to the following languages'=>'Limita aquest element de menú als idiomes següents','Date format'=>'Format de data','Customize the date formatting per each translated language.<br/>Leave empty for default WP setting or see more information <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">here</a>'=>'Personalitza el format de data per a cada idioma traduït.<br/>Deixa-ho en blanc per a la configuració per defecte del WP o consulta més informació <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">aquí</a>','To edit an existing TranslatePress language, input the language code and fill in only the columns you want to overwrite (e.g. Language name, Flag).<br>You can also add new custom languages. They will be available under General settings, All Languages list, where the URL slug can be edited.'=>'Per editar un idioma existent de TranslatePress, introdueix el codi de l\'idioma i omple només les columnes que vulguis sobreescriure (p. ex., Nom de l\'idioma, Bandera).<br>També pots afegir nous idiomes personalitzats. Estaran disponibles a Configuració general, a la llista Tots els idiomes, on es pot editar el slug de l\'URL.','For custom flag, first upload the image in media library then paste the URL.<br>Changing or deleting a custom language will impact translations and site URL\'s.<br>The Language code and the ISO Code should contain only alphabetical values, numerical values, "-" and "_".<br>The ISO Codes can be found on <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> and <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.'=>'Per a una bandera personalitzada, primer puja la imatge a la biblioteca multimèdia i després enganxa l\'URL.<br>Canviar o suprimir un idioma personalitzat afectarà les traduccions i els URL del lloc.<br>El codi d\'idioma i el codi ISO només han de contenir valors alfabètics, valors numèrics, "-" i "_".<br>Els codis ISO es troben a <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Codis ISO de Google</a> i <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">Codis de destinació del DeepL</a>.','Language code'=>'Codi d\'idioma','Language name'=>'Nom de l\'idioma','Native name'=>'Nom natiu','ISO Code'=>'Codi ISO','Flag URL'=>'URL de la bandera','Text RTL'=>'Text RTL','Custom language'=>'Idioma personalitzat','Disable dynamic translation'=>'Desactiva la traducció dinàmica','It disables detection of strings displayed dynamically using JavaScript. <br/>Strings loaded via a server side AJAX call will still be translated.'=>'Desactiva la detecció de cadenes mostrades dinàmicament mitjançant JavaScript. <br/>Les cadenes carregades mitjançant una crida AJAX del costat del servidor encara es traduiran.','Disable translation for gettext strings'=>'Desactiva la traducció de les cadenes Gettext','Gettext Strings are strings outputted by themes and plugins. <br> Translating these types of strings through TranslatePress can be unnecessary if they are already translated using the .po/.mo translation file system.<br>Enabling this option can improve the page load performance of your site in certain cases. The disadvantage is that you can no longer edit gettext translations using TranslatePress, nor benefit from automatic translation on these strings.'=>'Les cadenes Gettext són cadenes que generen els temes i els connectors. <br> Traduir aquestes cadenes amb TranslatePress pot ser innecessari si ja estan traduïdes amb el sistema de fitxers de traducció .po/.mo.<br>Activar aquesta opció pot millorar el rendiment de càrrega de la pàgina del teu lloc en certs casos. El desavantatge és que ja no podràs editar les traduccions Gettext amb TranslatePress, ni beneficiar-te de la traducció automàtica d\'aquestes cadenes.','Gettext Strings translation is disabled'=>'La traducció de cadenes Gettext està desactivada','To enable it go to '=>'Per a activar-ho, ves a ','TranslatePress->Advanced Settings->Debug->Disable translation for gettext strings'=>'TranslatePress->Configuració avançada->Depuració->Desactivar la traducció de les cadenes gettext',' and uncheck the Checkbox.'=>' i desmarca la casella de selecció.','Dismiss'=>'Descarta','Exclude translated links from sitemap'=>'Exclou els enllaços traduïts del sitemap','Do not include translated links in sitemaps generated by SEO plugins.<br/>Requires <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack Add-on</a> to be installed and activated.'=>'No incloure enllaços traduïts als sitemaps generats per plugins SEO.<br/>Requereix tenir instal·lat i activat el <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> complement SEO Pack</a>.','Disable post container tags for post title'=>'Desactiva les etiquetes contenidores de l\'entrada per al títol de l\'entrada','It disables search indexing the post title in translated languages.<br/>Useful when the title of the post doesn\'t allow HTML thus breaking the page.'=>'Desactiva la indexació de cerca del títol de l\'entrada en idiomes traduïts.<br/>Útil quan el títol de l\'entrada no admet HTML i, per tant, trenca la pàgina.','Disable post container tags for post content'=>'Desactiva les etiquetes contenidores de l\'entrada per al contingut','It disables search indexing the post content in translated languages.<br/>Useful when the content of the post doesn\'t allow HTML thus breaking the page.'=>'Desactiva la indexació de cerca del contingut de l\'entrada en idiomes traduïts.<br/>Útil quan el contingut de l\'entrada no admet HTML i, per tant, trenca la pàgina.','Do not translate certain paths'=>'No tradueixis certs camins','Choose what paths can be translated. Supports wildcard at the end of the path.<br>For example, to exclude https://example.com/some/path you can either use the rule /some/path/ or /some/*.<br>Enter each rule on it\'s own line. To exclude the home page use {{home}}.'=>'Tria quins camins es poden traduir. Admet comodins al final del camí.<br>Per exemple, per excloure https://example.com/some/path pots fer servir la regla /some/path/ o /some/*.<br>Introdueix cada regla en una línia pròpia. Per excloure la pàgina d\'inici, fes servir {home}.','Exclude Paths From Translation'=>'Exclou camins de la traducció','Translate Only Certain Paths'=>'Tradueix només certs camins','Enable the hreflang x-default tag for language:'=>'Habilita l\'etiqueta hreflang x-default per a l\'idioma:','Enables the hreflang="x-default" for an entire language. See documentation for more details.'=>'Habilita l\'hreflang="x-default" per a un idioma sencer. Consulta la documentació per a més detalls.','Translate numbers and numerals'=>'Tradueix nombres i numerals','Enable translation of numbers ( e.g. phone numbers)'=>'Habilita la traducció de nombres ( p. ex., números de telèfon)','Selector'=>'Selector','Exclude from dynamic translation'=>'Exclou de la traducció dinàmica','Do not dynamically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated using JavaScript.<br/>These strings will still be translated on the server side if possible.'=>'No tradueix dinàmicament les cadenes que es troben en nodes html que coincideixin amb aquests selectors.<br>Exclou tots els fills dels nodes HTML que coincideixin amb aquests selectors de ser traduïts amb JavaScript.<br/>Aquestes cadenes encara es traduiran al servidor si és possible.','Gettext String'=>'Cadena Gettext','Exclude Gettext Strings'=>'Exclou cadenes Gettext','Exclude these strings from being translated as Gettext strings by TranslatePress. Leave the domain empty to take into account any Gettext string.<br/>Can still be translated through po/mo files.'=>'Exclou aquestes cadenes de ser traduïdes com a cadenes Gettext per TranslatePress. Deixa el domini buit per tenir en compte qualsevol cadena Gettext.<br/>Encara es poden traduir mitjançant fitxers po/mo.','Exclude selectors only from automatic translation'=>'Exclou selectors només de la traducció automàtica','Do not automatically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being automatically translated.<br>Manual translation of these strings is still possible.'=>'No tradueix automàticament les cadenes que es troben en nodes html que coincideixin amb aquests selectors.<br>Exclou tots els fills dels nodes HTML que coincideixin amb aquests selectors de ser traduïts automàticament.<br>La traducció manual d\'aquestes cadenes encara és possible.','Exclude selectors from translation'=>'Exclou selectors de la traducció','Do not translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated.<br>These strings cannot be translated manually nor automatically.'=>'No tradueix les cadenes que es troben en nodes html que coincideixin amb aquests selectors.<br>Exclou tots els fills dels nodes HTML que coincideixin amb aquests selectors de ser traduïts.<br>Aquestes cadenes no es poden traduir manualment ni automàticament.','String'=>'Cadena','Exclude strings from automatic translation'=>'Exclou cadenes de la traducció automàtica','Do not automatically translate these strings (ex. names, technical words...)<br>Paragraphs containing these strings will still be translated except for the specified part.'=>'No tradueix automàticament aquestes cadenes (p. ex., noms, paraules tècniques...)<br>Els paràgrafs que continguin aquestes cadenes encara es traduiran excepte la part especificada.','Fix broken HTML'=>'Corregeix l\'HTML trencat','General attempt to fix broken or missing HTML on translated pages.<br/>'=>'Intent general de corregir l\'HTML trencat o que falta a les pàgines traduïdes.<br/>','Force slash at end of home url:'=>'Força la barra al final de l\'URL d\'inici:','Ads a slash at the end of the home_url() function'=>'Afegeix una barra al final de la funció home_url()','Show Both (recommended)'=>'Mostra tots dos (recomanat)','Remove Country Locale'=>'Elimina la configuració regional del país','Remove Region Independent Locale'=>'Elimina la configuració regional independent','Remove duplicate hreflang'=>'Elimina els hreflang duplicats','Choose which hreflang tags will appear on your website.<br/>We recommend showing both types of hreflang tags as indicated by <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Google documentation</a>.<br/>Removing Country Locale when having multiple Country Locales of the same language (ex. English UK and English US) will result in showing one hreflang tag with link to just one of the region locales for that language.'=>'Tria quines etiquetes hreflang apareixeran al teu lloc web.<br/>Recomanem mostrar els dos tipus d\'etiquetes hreflang, tal com indica la <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">documentació de Google</a>.<br/>Si se suprimeix la localització de país en tenir diverses localitzacions de país del mateix idioma (p. ex., anglès del Regne Unit i anglès dels Estats Units), es mostrarà una etiqueta hreflang amb un enllaç a només una de les localitzacions regionals d\'aquest idioma.','Default (example: en-US, fr-CA, etc.)'=>'Per defecte (exemple: en-US, fr-CA, etc.)','Regional (example: en, fr, es, etc.)'=>'Regional (exemple: en, fr, es, etc.)','HTML Lang Attribute Format'=>'Format de l\'atribut lang d\'HTML','Change lang attribute of the html tag to a format that includes country regional or not. <br>In HTML, the lang attribute (<html lang="en-US">)  should be used to  specify the language of text content so that the  browser can correctly display or process  your content (eg. for  hyphenation, styling, spell checking, etc).'=>'Canvia l\'atribut lang de l\'etiqueta html a un format que inclogui el país o no. <br>En HTML, l\'atribut lang (<html lang="en-US">) s\'hauria d\'utilitzar per especificar l\'idioma del contingut de text perquè el navegador pugui mostrar o processar correctament el contingut (p. ex., per a la separació sil·làbica, l\'estil, la correcció ortogràfica, etc.).','Load legacy Language Switcher'=>'Carrega el selector d\'idioma heretat','Applies to all types of language switchers (floating, shortcode, and menu). When enabled, the site will revert to using the original Language Switcher configured in the General Settings tab, replacing the new customizable version. Your existing switcher settings will remain saved, but they will be ignored while this option is active.'=>'S\'aplica a tots els tipus de selectors d\'idioma (flotant, shortcode i menú). Quan està activat, el lloc tornarà a utilitzar el selector d\'idioma original configurat a la pestanya Configuració general, substituint la nova versió personalitzable. La configuració existent del selector es mantindrà desada, però s\'ignorarà mentre aquesta opció estigui activa.','Load legacy SEO Pack Add-On'=>'Carrega el complement heretat SEO Pack','In case the recent migration to the new slug rewrite is causing trouble, set this to Yes to use the old method <br> Please <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">open a support ticket</a> letting us know of the issues you are having.'=>'Si la migració recent a la nova reescriptura de slug està causant problemes, estableix això a Sí per fer servir el mètode antic <br> Si us plau, <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">obre un tiquet de suport</a> fent-nos saber els problemes que tens.','Manual Translation Only'=>'Només traducció manual','TranslatePress pro-actively scans and saves strings in the database when users access translated pages. <br>This setting disables this functionality and only allows translation and string saving when inside the Translation Editor. <br>Also disables machine translation outside the Translation Editor, giving you better control over character spending, by translating only the pages you visit in the Translation Editor.'=>'TranslatePress escaneja i desa proactivament cadenes a la base de dades quan els usuaris accedeixen a pàgines traduïdes. <br>Aquesta configuració desactiva aquesta funcionalitat i només permet la traducció i el desament de cadenes quan es troba dins de l\'Editor de traducció. <br>També desactiva la traducció automàtica fora de l\'Editor de traducció, donant-te un millor control sobre el consum de caràcters, traduint només les pàgines que visitis a l\'Editor de traducció.','Open language switcher only on click'=>'Obre el selector d\'idioma només en fer clic','Open the language switcher shortcode by clicking on it instead of hovering.<br> Close it by clicking on it, anywhere else on the screen or by pressing the escape key. This will affect only the shortcode language switcher.'=>'Obre el shortcode del selector d\'idioma fent-hi clic en lloc de passar-hi el cursor per sobre.<br> Tanca\'l fent-hi clic, en qualsevol altre lloc de la pantalla o prement la tecla Esc. Això només afectarà el selector d\'idioma del shortcode.','Show opposite language in the language switcher'=>'Mostra l\'idioma oposat al selector d\'idioma','Transforms the language switcher into a button showing the other available language, not the current one.<br> Only works when there are exactly two languages, the default one and a translation one.<br>This will affect the shortcode language switcher and floating language switcher as well.<br> To achieve this in menu language switcher go to Appearance->Menus->Language Switcher and select Opposite Language.'=>'Transforma el selector d\'idioma en un botó que mostra l\'altre idioma disponible, no l\'actual.<br> Només funciona quan hi ha exactament dos idiomes, l\'idioma per defecte i un idioma de traducció.<br>Això també afectarà el selector d\'idioma del shortcode i el selector d\'idioma flotant.<br> Per aconseguir-ho al selector d\'idioma del menú, ves a Aparença->Menús->Selector d\'idioma i selecciona Idioma oposat.','<a href="%s">Click here</a> to access the database optimization tool.'=>'<a href="%s">Fes clic aquí</a> per accedir a l\'eina d\'optimització de la base de dades.','It helps remove possible duplicate translations, clear unnecessary data and repair possible metadata issues.'=>'Ajuda a eliminar possibles traduccions duplicades, netejar dades innecessàries i reparar possibles problemes de metadades.','<a href="%s" target="_blank">Here</a> you can observe the last 5 SQL errors relevant to TranslatePress if they exist.'=>'<a href="%s" target="_blank">Aquí</a> pots observar els últims 5 errors SQL rellevants per al TranslatePress, si n\'hi ha.','Troubleshooting'=>'Resolució de problemes','Exclude Gettext strings'=>'Exclou cadenes Gettext','Debug'=>'Depuració','Custom languages'=>'Idiomes personalitzats','Miscellaneous options'=>'Opcions diverses','Exclude strings & pages'=>'Exclou cadenes i pàgines','Automatic Translation Memory'=>'Memòria de traducció automàtica','Serve same translation for similar text. The strings need to have a percentage of 95% similarity.<br>Helps prevent losing existing translation when correcting typos or making minor adjustments to the original text. <br>If a translation already exists for a very similar original string, it will automatically be used for the current original string.<br>Does not work when making changes to a text that is part of a translation block unless the new text is manually merged again in a translation block.<br>Each string needs to have a minimum of 50 characters.'=>'Proporciona la mateixa traducció per a textos similars. Les cadenes han de tenir un percentatge de similitud del 95%.<br>Ajuda a evitar perdre traduccions existents en corregir errades tipogràfiques o fer petits ajustos al text original. <br>Si ja existeix una traducció per a una cadena original molt similar, s\'utilitzarà automàticament per a la cadena original actual.<br>No funciona quan es fan canvis a un text que forma part d\'un bloc de traducció, tret que el text nou es fusioni manualment de nou en un bloc de traducció.<br>Cada cadena ha de tenir un mínim de 50 caràcters.','WARNING: This feature can negatively impact page loading times in secondary languages, particularly with large databases (for example websites with a lot of pages or products). If you experience slow loading times, disable this and try again.'=>'AVÍS: Aquesta funció pot afectar negativament els temps de càrrega de les pàgines en idiomes secundaris, especialment amb bases de dades grans (per exemple, llocs web amb moltes pàgines o productes). Si experimentes temps de càrrega lents, desactiva-ho i torna-ho a provar.','Fix missing dynamic content'=>'Corregeix el contingut dinàmic que falta','May help fix missing content inserted using JavaScript. <br> It shows dynamically inserted content in original language for a moment before the translation request is finished.'=>'Pot ajudar a corregir el contingut que falta inserit amb JavaScript. <br> Mostra el contingut inserit dinàmicament en l\'idioma original un moment abans que la sol·licitud de traducció finalitzi.','Filter Gettext wrapping from post content and title'=>'Filtra l\'embolcall Gettext del contingut i el títol de l\'entrada','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post content and post title. Does not affect previous post content. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtra l\'embolcall gettext, com ara #!trpst#trp-gettext, de tot el contingut i els títols d\'entrada actualitzats. No afecta el contingut d\'entrada anterior. <br/><strong>Es recomana fer una còpia de seguretat de la base de dades abans d\'activar-ho.</strong>','Filter Gettext wrapping from post meta'=>'Filtra l\'embolcall Gettext de les metadades de l\'entrada','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post meta. Does not affect previous post meta. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtra l\'embolcall gettext, com ara #!trpst#trp-gettext, de totes les metadades d\'entrada actualitzades. No afecta les metadades d\'entrada anteriors. <br/><strong>Es recomana fer una còpia de seguretat de la base de dades abans d\'activar-ho.</strong>','Google Translate v2'=>'Google Translate v2','Google Translate API Key'=>'Clau de l\'API de Google Translate','Add your API Key here...'=>'Afegeix la teva clau de l\'API aquí...','Visit <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">this link</a> to see how you can set up an API key, <strong>control API costs</strong> and set HTTP referrer restrictions.'=>'Visita <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">aquest enllaç</a> per veure com pots configurar una clau de l\'API, <strong>controlar els costos de l\'API</strong> i establir restriccions del referent HTTP.','Your HTTP referrer is: %s'=>'El teu referent HTTP és: %s','There was an error on the server processing your Google Translate key.'=>'S\'ha produït un error al servidor en processar la teva clau de Google Translate.','There was an error with your Google Translate key.'=>'S\'ha produït un error amb la teva clau de Google Translate.','Please check your TranslatePress license key.'=>'Si us plau, comprova la teva clau de llicència de TranslatePress.','TranslatePress AI'=>'TranslatePress AI','No Active License Detected for this website.'=>'No s\'ha detectat cap llicència activa per a aquest lloc web.','In order to enable Automatic Translation using TranslatePress AI, you need a license key by creating a free account.'=>'Per habilitar la traducció automàtica amb TranslatePress AI, has d\'obtenir una clau de llicència creant un compte gratuït.','Create your Free Account'=>'Crea el teu compte gratuït',' or '=>' o ','Enter your license key'=>'Introdueix la teva clau de llicència',' Or %1$spurchase one here%2$s'=>' O %1$scompra\'n una aquí%2$s','Your free account includes: '=>'El teu compte gratuït inclou: ','Get more AI Words and unlock all AI features with TranslatePress Pro.'=>'Aconsegueix més paraules d\'IA i desbloqueja totes les funcions d\'IA amb TranslatePress Pro.','You have a valid %s <strong>license</strong>.'=>'Tens una <strong>llicència</strong> vàlida de %s.',' words remaining. '=>' paraules restants. ','Recheck'=>'Torna a comprovar','Rechecking...'=>'S\'està comprovant de nou...','Done.'=>'Fet.','Manage your license & quota on the %s'=>'Gestiona la teva llicència i quota a la %s','TranslatePress.com Account Page'=>'Pàgina del compte de TranslatePress.com','SEO support for page slug, page title, description and Facebook and Twitter social graph information. The HTML lang attribute is properly set.'=>'Suport SEO per al slug, el títol i la descripció de la pàgina, i la informació del gràfic social de Facebook i Twitter. L\'atribut lang de l\'HTML s\'estableix correctament.','Enable Modules'=>'Habilita els mòduls','Enable Add-on modules to extend TranslatePress and enhance the functionality of your translated site.'=>'Habilita els mòduls complementaris per ampliar TranslatePress i millorar la funcionalitat del teu lloc traduït.','More functionality with TranslatePress Pro.'=>'Més funcionalitat amb TranslatePress Pro.','Already a Pro User?'=>'Ja ets usuari Pro?','Activate License Key'=>'Activa la clau de llicència','This add-on is not available on your current plan.'=>'Aquest complement no està disponible al teu pla actual.','Continue'=>'Continua','The link you followed has expired. Please reload the page and try again.'=>'L\'enllaç que has seguit ha caducat. Si us plau, torna a carregar la pàgina i torna-ho a provar.','A valid license is required to enable Automatic Translation.'=>'Cal una llicència vàlida per activar la traducció automàtica.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Manage Sites.'=>'La clau de llicència està desactivada per a aquesta URL. Reactiva-la des de <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Gestiona els llocs.','<p><strong>License key mismatch.</strong> The license you entered doesn\'t match the TranslatePress version you have installed.</p><p>Please check that you\'ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>La clau de llicència no coincideix.</strong> La llicència que has introduït no coincideix amb la versió del TranslatePress que tens instal·lada.</p><p>Comprova que has instal·lat la versió correcta per a la teva llicència des del teu compte del TranslatePress.</p>','Automatically translate your website using TranslatePress AI.'=>'Tradueix automàticament el teu lloc web amb el TranslatePress AI.','In order to enable Automatic Translation using TranslatePress AI, please enter your license key from'=>'Per activar la traducció automàtica amb el TranslatePress AI, introdueix la clau de llicència de','your account.'=>'el teu compte.','Skip and continue with manual translation »'=>'Omet i continua amb la traducció manual »','Get Your Free TranslatePress AI License'=>'Aconsegueix la teva llicència gratuïta del TranslatePress AI','Generate License'=>'Genera la llicència','Creating a free account includes: '=>'Crear un compte gratuït inclou: ','Are you a TranslatePress PRO user?'=>'Ets usuari del TranslatePress PRO?','Install & Activate your pro plugin.'=>'Instal·la i activa el teu plugin pro.','Skip this step'=>'Omet aquest pas','The email address you added is incorrect.'=>'L\'adreça de correu electrònic que has afegit és incorrecta.','Setup Complete'=>'Configuració completada','You\'re ready to start translating!'=>'Estàs llest per començar a traduir!','You have successfully set up TranslatePress for your website.'=>'Has configurat el TranslatePress correctament per al teu lloc web.','Receive '=>'Rep ','Yes, send me multilingual growth tips.'=>'Sí, envia\'m consells de creixement multilingüe.','Start translating'=>'Comença a traduir','Sign Up and Start translating'=>'Registra\'t i comença a traduir','Please upload a TranslatePress Pro plugin file.'=>'Si us plau, puja un fitxer del connector TranslatePress Pro.','Upload error: '=>'Error de pujada: ','Install failed: '=>'La instal·lació ha fallat: ','Plugin installed, but entry file not found. '=>'S\'ha instal·lat el connector, però no s\'ha trobat el fitxer d\'entrada. ','Activation error: '=>'Error d\'activació: ','Invalid plugin specified.'=>'S\'ha especificat un connector no vàlid.','Invalid action specified.'=>'S\'ha especificat una acció no vàlida.','Plugin deactivation failed.'=>'La desactivació del connector ha fallat.','Plugin activation failed: '=>'L\'activació del connector ha fallat: ','First, install and activate TranslatePress Pro'=>'Primer, instal·la i activa el TranslatePress Pro','Please upload the TranslatePress PRO zip archive from your'=>'Si us plau, puja l\'arxiu zip del TranslatePress Pro des del teu','TranslatePress Account'=>'TranslatePress Account','Install and Activate'=>'Instal·la i activa','Installed Pro versions'=>'Versions Pro instal·lades','« Go back'=>'« Torna enrere','Activate License »'=>'Activa la llicència »','You are trying to add an invalid additional language. Please select a valid option.'=>'Estàs intentant afegir un idioma addicional no vàlid. Si us plau, selecciona una opció vàlida.','Please add an additional language.'=>'Si us plau, afegeix un idioma addicional.','You are trying to add an invalid default language. Please select a valid option.'=>'Estàs intentant afegir un idioma per defecte no vàlid. Si us plau, selecciona una opció vàlida.','You need to select a default language.'=>'Has de seleccionar un idioma per defecte.','Configure Site Languages'=>'Configura els idiomes del lloc','Select the default and additional languages for your website.'=>'Selecciona l\'idioma per defecte i els idiomes addicionals del teu lloc web.','You can edit your site languages at any point.'=>'Pots editar els idiomes del lloc en qualsevol moment.','Additional Language'=>'Idioma addicional','Choose a secondary language...'=>'Tria un idioma secundari...','Add Language'=>'Afegeix un idioma','Choose a language...'=>'Tria un idioma...','Add more than two languages with TranslatePress Pro.'=>'Afegeix més de dos idiomes amb TranslatePress Pro.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=activate-license">https://translatepress.com/account</a> -> Manage Sites.'=>'La teva clau de llicència està desactivada per a aquesta URL. Reactiva-la des de <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=activate-license">https://translatepress.com/account</a> -> Gestiona els llocs.','Add your License Key'=>'Afegeix la clau de llicència','Add your License Key to unlock all premium features. Find the License Key in your'=>'Afegeix la clau de llicència per desbloquejar totes les funcions premium. Troba la clau de llicència al teu','Your license is valid and active.'=>'La teva llicència és vàlida i activa.','« Go Back'=>'« Torna enrere','Set up Language Switcher'=>'Configura el selector d\'idioma','Select the style of the language switcher. You will find more ways to display it, in plugin settings.'=>'Selecciona l\'estil del selector d\'idioma. Trobaràs més maneres de mostrar-lo a la configuració del connector.','Displays a small language drop-down across your website, in a corner of your choosing.'=>'Mostra un petit desplegable d\'idioma per tot el teu lloc web, a la cantonada que triïs.','Switcher Location'=>'Ubicació del selector','Apply a Template'=>'Aplica una plantilla','You can customize the design later'=>'Pots personalitzar el disseny més tard','Default Template'=>'Plantilla per defecte','Dark Template'=>'Plantilla fosca','Border Template'=>'Plantilla amb vora','Border'=>'Vora','Transparent Template'=>'Plantilla transparent','Transparent'=>'Transparent','Welcome to TranslatePress'=>'Benvingut a TranslatePress','Quick guided setup to configure TranslatePress in no time!'=>'Configuració guiada ràpida per configurar TranslatePress en un tres i no res!','It takes less than a minute.'=>'Triga menys d\'un minut.','Scanning item %1$d of %2$d...'=>'S\'està escanejant l\'element %1$d de %2$d...','Manually translated'=>'Traduït manualment','Automatically translated'=>'Traduït automàticament','Not translated'=>'No traduït','Bulk Actions'=>'Accions massives','Delete entries'=>'Suprimeix les entrades','Edit'=>'Edita','Delete'=>'Suprimeix','Filter'=>'Filtra','Clear filters'=>'Neteja els filtres','Add New'=>'Afegeix-ne un de nou','Rescan plugins and theme for strings'=>'Torna a escanejar els connectors i el tema per trobar cadenes','Scanning plugins and theme for strings...'=>'S\'estan escanejant els connectors i el tema per trobar cadenes...','Plugins and theme scan is complete'=>'S\'ha completat l\'escaneig dels connectors i el tema','Plugins and theme scan did not finish due to an error'=>'L\'escaneig dels connectors i el tema no ha acabat a causa d\'un error','Import / Export'=>'Importació / Exportació','items'=>'elements','See More'=>'Veure més','See Less'=>'Veure menys','Apply'=>'Aplica','No strings match your query.'=>'Cap cadena coincideix amb la consulta.','Try to rescan plugins and theme for strings.'=>'Prova de tornar a escanejar els connectors i el tema per trobar cadenes.','An error occurred while loading results. Most likely you were logged out. Reload page?'=>'S\'ha produït un error en carregar els resultats. Probablement has tancat la sessió. Vols recarregar la pàgina?','found in translation'=>'trobada a la traducció','Select All'=>'Selecciona-ho tot','Select Visible'=>'Selecciona els visibles','You are about to perform this action on all the strings matching your filter, not just the visibly checked. To perform the action only to the visible strings click "Select Visible" from the table header dropdown.'=>'Estàs a punt de realitzar aquesta acció a totes les cadenes que coincideixen amb el filtre, no només les que estan marcades visiblement. Per realitzar l\'acció només a les cadenes visibles, fes clic a "Selecciona les visibles" al menú desplegable de la capçalera de la taula.','You are about to perform this action only on the visible strings. To perform the action on all the strings matching the filter click "Select All" from the table header dropdown.'=>'Estàs a punt de realitzar aquesta acció només a les cadenes visibles. Per realitzar l\'acció a totes les cadenes que coincideixen amb el filtre, fes clic a "Selecciona-ho tot" al menú desplegable de la capçalera de la taula.','To continue please type the word:'=>'Per continuar, escriu la paraula:','The word typed was incorrect. Action was cancelled.'=>'La paraula escrita era incorrecta. S\'ha cancel·lat l\'acció.','Warning: This action cannot be undone. Deleting a string will remove its current translation. The original string will appear again in this interface after TranslatePress detects it. This action is NOT equivalent to excluding the string from being translated again.'=>'Avís: Aquesta acció no es pot desfer. Eliminar una cadena suprimirà la seva traducció actual. La cadena original tornarà a aparèixer en aquesta interfície després que TranslatePress la detecti. Aquesta acció NO equival a excloure la cadena perquè no es torni a traduir.','%d original entries and their translations were deleted.'=>'%d entrades originals i les seves traduccions s\'han suprimit.','Navigate to next page'=>'Navega a la pàgina següent','Navigate to previous page'=>'Navega a la pàgina anterior','Navigate to first page'=>'Navega a la primera pàgina','Navigate to last page'=>'Navega a l\'última pàgina','Type a page number to navigate to'=>'Escriviu un número de pàgina per navegar-hi','Incorrect page number. Type a page number between 1 and total number of pages'=>'Número de pàgina incorrecte. Escriviu un número de pàgina entre 1 i el nombre total de pàgines','Search original and translated strings containing typed keywords while also matching selected filters. Place string in quotes for exact match: "string"'=>'Cerca cadenes originals i traduïdes que continguin les paraules clau introduïdes tot coincidint amb els filtres seleccionats. Posa la cadena entre cometes per a una coincidència exacta: "cadena"','Filter strings according to selected translation status, filters and keywords and selected filters'=>'Filtra les cadenes segons l\'estat de traducció seleccionat, els filtres i les paraules clau i els filtres seleccionats.','Removes selected filters'=>'Elimina els filtres seleccionats','See options for selecting all strings'=>'Veure les opcions per seleccionar totes les cadenes','Click to sort strings by this column'=>'Fes clic per ordenar les cadenes per aquesta columna','Language in which the translation status filter applies. Leave unselected for the translation status to apply to ANY language'=>'Idioma en què s\'aplica el filtre d\'estat de traducció. Deixeu-ho sense seleccionar perquè l\'estat de traducció s\'apliqui a QUALSEVOL idioma','Search'=>'Cerca','Slugs that are not found in either one of the other categories.'=>'Slugs que no es troben en cap de les altres categories.','Plugins and Theme String Translation'=>'Traducció de cadenes de connectors i tema','Gettext'=>'Gettext','Search Gettext Strings'=>'Cerca cadenes Gettext','ID'=>'ID','Original String'=>'Cadena original','Translation'=>'Traducció','Filter by domain'=>'Filtra per domini','Filter by type'=>'Filtra per tipus','Email text'=>'Text del correu electrònic','Emails String Translation'=>'Traducció de cadenes de correu electrònic','Emails'=>'Correus electrònics','Search Email Strings'=>'Cercar cadenes de correu electrònic','User Inputted String Translation'=>